update cpinfo
set ActualRemain = ActualRemain - #{amount},
    FrozenRemain = FrozenRemain + #{amount}
where AppId = #{appId}
  and ActualRemain >= #{amount}

update cpinfo
set googleSecret = #{googleSecret}
where AppId = #{appId}

